arguments.content:
* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: #1a1a2e;
  color: #e0e0e0;
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding-top: 10vh;
}

.container {
  width: 100%;
  max-width: 480px;
  padding: 2rem;
}

h1 {
  font-size: 2rem;
  margin-bottom: 1.5rem;
  text-align: center;
}

#search-form {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 2rem;
}

#city-input {
  flex: 1;
  padding: 0.75rem 1rem;
  border: 1px solid #333;
  border-radius: 8px;
  background: #16213e;
  color: #fff;
  font-size: 1rem;
}

button {
  padding: 0.75rem 1.5rem;
  background: #0f3460;
  color: #fff;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 1rem;
  transition: background 0.2s;
}

button:hover { background: #1a5276; }

#weather-card {
  background: #16213e;
  border-radius: 16px;
  padding: 2rem;
  text-align: center;
}

.weather-header {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1rem;
  margin-bottom: 1rem;
}

#weather-icon { width: 64px; height: 64px; }

.temp-display {
  font-size: 4rem;
  font-weight: 700;
  margin: 1rem 0;
}

.unit { font-size: 1.5rem; opacity: 0.6; }

#description {
  text-transform: capitalize;
  opacity: 0.8;
  margin-bottom: 1.5rem;
}

.details {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1rem;
  border-top: 1px solid #333;
  padding-top: 1rem;
}

.details div {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.details span:first-child {
  font-size: 0.75rem;
  text-transform: uppercase;
  opacity: 0.5;
}

.hidden { display: none; }

#error {
  text-align: center;
  color: #e74c3c;
  padding: 1rem;
}

const form = document.getElementById('search-form');
const input = document.getElementById('city-input');
const card = document.getElementById('weather-card');
const error = document.getElementById('error');

form.addEventListener('submit', async (e) => {
  e.preventDefault();
  const city = input.value.trim();
  if (!city) return;

  error.classList.add('hidden');
  card.classList.add('hidden');

  try {
    const res = await fetch(`/api/weather/${encodeURIComponent(city)}`);
    if (!res.ok) {
      const data = await res.json();
      throw new Error(data.error || 'Failed to fetch weather');
    }
    const data = await res.json();
    renderWeather(data);
  } catch (err) {
    error.textContent = err.message;
    error.classList.remove('hidden');
  }
});

function renderWeather(data) {
  document.getElementById('city-name').textContent = data.city;
  document.getElementById('country').textContent = data.country;
  document.getElementById('temperature').textContent = Math.round(data.temp);
  document.getElementById('description').textContent = data.description;
  document.getElementById('feels-like').textContent = Math.round(data.feelsLike) + '°C';
  document.getElementById('humidity').textContent = data.humidity + '%';
  document.getElementById('wind').textContent = data.windSpeed + ' m/s';
  document.getElementById('weather-icon').src =
    `https://openweathermap.org/img/wn/${data.icon}@2x.png`;
  card.classList.remove('hidden');
}

